#include<cstdio>
#include<cstring> 
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define grep(b,c) for(int c=head[(b)];c;c=nxt[c])
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline T min(const T &x,const T &y){return x<y?x:y;}
const int N=1e6+10,M=2e6+10;int head[N],des[M],nxt[M],cgt=1,cap[M],n,m,s,t;bool vis[N],col[N];
inline void ins(const int &x,const int &y){nxt[++cgt]=head[x];des[head[x]=cgt]=y;nxt[++cgt]=head[y];des[head[y]=cgt]=x;}
inline void ins(const int &x,const int &y,const int &z)
{
	nxt[++cgt]=head[x];des[head[x]=cgt]=y;cap[cgt]=z;
	nxt[++cgt]=head[y];des[head[y]=cgt]=x;cap[cgt]=0;
}
inline void dfs(const int &u,const bool &c=0){vis[u]=true;col[u]=c;grep(u,i)if(!vis[des[i]])dfs(des[i],c^1);}
namespace MaxFlow
{
	int que[N],dep[N],H,T;inline bool bfs()
	{
		memset(dep,0,sizeof(dep));dep[que[H=T=1]=s]=1;
		while(H<=T){int u=que[H++];grep(u,i)if(cap[i]&&!dep[des[i]])dep[que[++T]=des[i]]=dep[u]+1;}return dep[t];
	}
	inline int dfs(const int &u=s,int in=0x3f3f3f3f)
	{
		if(u==t)return in;int out(0);grep(u,i)
		{
			if(dep[des[i]]==dep[u]+1)
			{
				int tmp=dfs(des[i],min(in,cap[i]));
				cap[i]-=tmp;cap[i^1]+=tmp;in-=tmp;out+=tmp;
			}
			if(!in)break;
		}
		if(!out)dep[u]=0;return out;
	}
	inline int dinic(){int res=0;while(bfs())res+=dfs();return res;}
}
using MaxFlow::dinic;
int main()
{
	n=read();m=read();rep(1,m,i)ins(read()+1,read()+1);s=n<<1|1;t=(n+1)<<1;
	rep(1,n,i)if(!vis[i])dfs(i);rep(1,n,i)col[i]?ins(i,t,1):ins(s,i,1);
	for(int i=2;i<=cgt;i+=2)cap[(!col[des[i]])^i]=1;printf("%d\n",n-dinic());
}
